1	import { existsSync, mkdirSync } from "node:fs";
2	import path from "node:path";
3	
4	/**
5	 * 每个 WeChat Bot（dashboard 用户 `userId`）对应 **一个** pi-coding-agent 会话；
6	 * 其 **cwd / read / wechat_send 本地路径** 的根目录均为：
7	 *   `<项目根>/.data/wechatbot/<userId>/`
8	 *
9	 * 与 `WECHATBOT_STORAGE_DIR`（SDK 凭据，默认 ~/.wechatbot）互相独立。
10	 */
11	export function wechatbotAgentWorkspace(userId: string): string {
12	  const root = path.resolve(process.cwd(), ".data", "wechatbot", userId);
13	  if (!existsSync(root)) {
14	    mkdirSync(root, { recursive: true });
15	  }
16	  return root;
17	}
