1	import { existsSync, readFileSync, readdirSync, rmSync } from "node:fs";
2	import path from "node:path";
3	import { WeChatBot, type Credentials } from "@wechatbot/wechatbot";
4	import { eq } from "drizzle-orm";
5	import { wechatStorageBase } from "@/lib/wechat-storage";
6	import { db } from "@/lib/db";
7	import { wechatBotAutostart } from "@cau-claw/db";
8	import { agentService } from "@/modules/agent/service";
9	import { cronService } from "@/modules/cron/service";
10	import { reminderService } from "@/modules/reminder/service";
11	import type { BotStatusPayload } from "@/lib/bot/types";
12	
13	export type BotStatus = "idle" | "waiting_scan" | "online" | "error";
14	
15	interface BotEntry {
16	  bot: WeChatBot;
17	  status: BotStatus;
18	  qrUrl?: string;
19	  credentials?: Credentials;
20	  error?: string;
21	}
22	
23	function removeUserWechatStorage(userId: string): void {
24	  const dir = path.join(wechatStorageBase(), userId);
25	  try {
26	    if (!existsSync(dir)) return;
27	    rmSync(dir, { recursive: true, force: true });
28	    console.log(`[bot user:${userId}] 已删除本地凭据目录: ${dir}`);
29	  } catch (e) {
30	    console.warn(`[bot user:${userId}] 删除凭据目录失败: ${dir}`, e);
31	  }
32	}
33	
34	/**
35	 * 从本地目录发现已有 credentials.json 的用户，补全 autostart 表。
36	 */
37	async function seedAutostartFromCredentialFiles(): Promise<number> {
38	  const base = wechatStorageBase();
39	  let n = 0;
40	  let names: string[];
41	  try {
42	    names = readdirSync(base);
43	  } catch {
44	    return 0;
45	  }
46	  for (const name of names) {
47	    const credPath = path.join(base, name, "credentials.json");
48	    if (!existsSync(credPath)) continue;
49	    try {
50	      await db
51	        .insert(wechatBotAutostart)
52	        .values({ userId: name, updatedAt: new Date() })
53	        .onConflictDoNothing();
54	      n++;
55	    } catch {
56	      /* FK：无对应 user */
57	    }
58	  }
59	  if (n) {
60	    console.log(`[bot] 已从本地凭据目录补全 ${n} 条自动恢复标记`);
61	  }
62	  return n;
63	}
64	
65	/** 从本地 credentials.json 读取微信号（SDK 落地文件名），用于内存里尚未带齐字段时的展示兜底 */
66	function readStoredAccountId(userId: string): string | undefined {
67	  const credPath = path.join(wechatStorageBase(), userId, "credentials.json");
68	  if (!existsSync(credPath)) return undefined;
69	  try {
70	    const raw = readFileSync(credPath, "utf8");
71	    const parsed = JSON.parse(raw) as { accountId?: unknown };
72	    return typeof parsed.accountId === "string" ? parsed.accountId : undefined;
73	  } catch {
74	    return undefined;
75	  }
76	}
