78	export class BotService {
79	  private bots = new Map<string, BotEntry>();
80	  /** 与 `wechat_bot_autostart` 同步，供仪表盘展示「自动恢复」 */
81	  private autostartCache = new Map<string, boolean>();
82	  /** 同步互斥：同一 userId 上并发 `startBot`（双 SSE、ensure+restore 竞态）只跑一条连接流程 */
83	  private pendingBotStart = new Set<string>();
84	
85	  // ── 启动门控：init 恢复完成前阻塞懒启动与状态查询 ──────────────────
86	
87	  private _restoreDone = false;
88	  private _restoreResolve: (() => void) | undefined;
89	  /**
90	   * 进程启动时 `restorePersistedBots()` 完成（或失败）后 resolve。
91	   * API 路由调用 `awaitRestore()` 后再做懒启动，避免与 init 竞态。
92	   */
93	  readonly afterRestore = new Promise<void>((res) => {
94	    this._restoreResolve = res;
95	  });
96	
97	  /** 由 `restorePersistedBots` 的 finally 调用（独立 worker 进程）。 */
98	  signalRestoreComplete(): void {
99	    if (this._restoreDone) return;
100	    this._restoreDone = true;
101	    this._restoreResolve?.();
102	  }
103	
104	  /**
105	   * 等待 `restorePersistedBots` 完成，随后若本地存有凭据且进程内还无该用户 Bot，
106	   * 则触发懒启动（冷启动/新 worker 场景的兜底）。
107	   */
108	  async ensureStarted(userId: string): Promise<void> {
109	    await this.afterRestore;
110	    if (!this.hasLocalCredentials(userId)) return;
111	    if (this.bots.has(userId)) return;
112	    this.startBot(userId);
113	  }
114	
115	  getStatus(userId: string): BotStatusPayload {
116	    const autostart =
117	      this.autostartCache.get(userId) === true ||
118	      this.hasLocalCredentials(userId);
119	    const entry = this.bots.get(userId);
120	    if (!entry) {
121	      return { status: "idle" as BotStatus, autostart };
122	    }
123	    let accountId = entry.credentials?.accountId;
124	    if (!accountId && entry.status === "online") {
125	      const fromDisk = readStoredAccountId(userId);
126	      if (fromDisk) {
127	        accountId = fromDisk;
128	        if (entry.credentials) {
129	          entry.credentials = { ...entry.credentials, accountId: fromDisk };
130	        }
131	      }
132	    }
133	    return {
134	      status: entry.status,
135	      qrUrl: entry.qrUrl,
136	      accountId,
137	      error: entry.error,
138	      autostart,
139	    };
140	  }
141	
142	  private async persistAutostart(userId: string): Promise<void> {
143	    try {
144	      await db
145	        .insert(wechatBotAutostart)
146	        .values({ userId, updatedAt: new Date() })
147	        .onConflictDoUpdate({
148	          target: wechatBotAutostart.userId,
149	          set: { updatedAt: new Date() },
150	        });
151	      this.autostartCache.set(userId, true);
152	    } catch (e) {
153	      console.warn(`[bot] 写入 wechat_bot_autostart 失败 user ${userId}`, e);
154	    }
155	  }
156	
157	  getBot(userId: string): WeChatBot | undefined {
158	    return this.bots.get(userId)?.bot;
159	  }
160	
161	  isOnline(userId: string): boolean {
162	    return this.bots.get(userId)?.status === "online";
163	  }
164	
165	  startBot(
166	    userId: string,
167	    opts?: { force?: boolean },
168	  ): { ok: true } | { error: string } {
169	    const existing = this.bots.get(userId);
170	    if (existing?.status === "online") {
171	      return { ok: true };
172	    }
173	    if (existing?.status === "waiting_scan") {
174	      return { ok: true };
175	    }
176	
177	    if (opts?.force) {
178	      this.pendingBotStart.delete(userId);
179	    } else if (this.pendingBotStart.has(userId)) {
180	      return { ok: true };
181	    }
182	    this.pendingBotStart.add(userId);
183	
184	    existing?.bot.stop();
185	
186	    const base = wechatStorageBase();
187	
188	    let bot: WeChatBot;
189	    try {
190	      bot = new WeChatBot({
191	      storage: "file",
192	      storageDir: `${base}/${userId}`,
193	      logLevel: (process.env.WECHATBOT_LOG_LEVEL as "debug" | "info" | "warn" | "error") ?? "info",
194	    });
195	    } catch (e) {
196	      this.pendingBotStart.delete(userId);
197	      throw e;
198	    }
199	
200	    const entry: BotEntry = { bot, status: "idle" };
201	    this.bots.set(userId, entry);
202	
203	    void (async () => {
204	      try {
205	        const creds = await bot.login({
206	          callbacks: {
207	            onQrUrl: (url) => {
208	              entry.qrUrl = url;
209	              entry.status = "waiting_scan";
210	              console.log(`[bot user:${userId}] QR: ${url}`);
211	            },
212	            onScanned: () => {
213	              console.log(`[bot user:${userId}] 已扫码，等待确认`);
214	            },
215	            onExpired: () => {
216	              console.log(`[bot user:${userId}] 二维码过期`);
217	            },
218	          },
219	        });
220	
221	        // 并发再次 startBot 时，新实例会替换 map；本段若继续挂 handler/start，会与旧/新实例叠成两条轮询或双 onMessage。
222	        if (this.bots.get(userId)?.bot !== bot) {
223	          console.log(
224	            `[bot user:${userId}] 已跳过过期登录流程（已被新的连接请求替换）`,
225	          );
226	          return;
227	        }
228	
229	        entry.credentials = creds;
230	        entry.status = "online";
231	        entry.qrUrl = undefined;
232	        await this.persistAutostart(userId);
233	        console.log(`[bot user:${userId}] 已上线: ${creds.accountId}`);
234	
235	        bot.on("session:expired", async () => {
236	          console.warn(`[bot user:${userId}] 会话过期，自动重连...`);
237	          entry.status = "waiting_scan";
238	        });
239	
240	        bot.on("session:restored", async (c) => {
241	          entry.credentials = c;
242	          entry.status = "online";
243	          await this.persistAutostart(userId);
244	          console.log(`[bot user:${userId}] 已重连: ${c.accountId}`);
245	        });
246	
247	        bot.on("error", (err) => {
248	          console.error(`[bot user:${userId}] error:`, err);
249	        });
250	
251	        // SDK 的 onMessage 为 push；解绑再绑或重复连接时须避免同一实例上挂多个 handler。
252	        const sink = bot as unknown as { messageHandlers?: unknown[] };
253	        if (Array.isArray(sink.messageHandlers)) {
254	          sink.messageHandlers.length = 0;
255	        }
256	
257	        bot.onMessage((msg) => {
258	          if (this.bots.get(userId)?.bot !== bot) return;
259	          agentService.enqueue(userId, () =>
260	            agentService.handleWechatMessage(userId, bot, msg),
261	          );
262	        });
263	
264	        if (this.bots.get(userId)?.bot !== bot) {
265	          return;
266	        }
267	
268	        bot.start().catch((err) => {
269	          entry.status = "error";
270	          entry.error = err instanceof Error ? err.message : String(err);
271	          console.error(`[bot user:${userId}] polling error:`, err);
272	        });
273	      } catch (err) {
274	        if (this.bots.get(userId)?.bot !== bot) {
275	          return;
276	        }
277	        entry.status = "error";
278	        entry.error = err instanceof Error ? err.message : String(err);
279	        console.error(`[bot user:${userId}] login error:`, err);
280	      } finally {
281	        this.pendingBotStart.delete(userId);
282	      }
283	    })();
284	
285	    return { ok: true };
286	  }
287	
288	  private hasLocalCredentials(userId: string): boolean {
289	    return existsSync(
290	      path.join(wechatStorageBase(), userId, "credentials.json"),
291	    );
292	  }
293	
294	  async restorePersistedBots(): Promise<void> {
295	    try {
296	      await seedAutostartFromCredentialFiles();
297	      const rows = await db
298	        .select({ userId: wechatBotAutostart.userId })
299	        .from(wechatBotAutostart);
300	      this.autostartCache.clear();
301	      for (const { userId } of rows) {
302	        this.autostartCache.set(userId, true);
303	      }
304	      let started = 0;
305	      for (const { userId } of rows) {
306	        if (!this.hasLocalCredentials(userId)) {
307	          console.log(
308	            `[bot user:${userId}] 跳过自动连接：本地无凭据，需用户手动扫码`,
309	          );
310	          continue;
311	        }
312	        this.startBot(userId);
313	        started++;
314	      }
315	      console.log(
316	        `[bot] 已发起 ${started} 个微信 Bot 自动连接（凭本地存储的 credentials）`,
317	      );
318	    } finally {
319	      this.signalRestoreComplete();
320	    }
321	  }
322	
323	  async stopBot(userId: string): Promise<void> {
324	    this.pendingBotStart.delete(userId);
325	    const entry = this.bots.get(userId);
326	    if (entry) {
327	      entry.bot.stop();
328	      this.bots.delete(userId);
329	    }
330	    try {
331	      await db
332	        .delete(wechatBotAutostart)
333	        .where(eq(wechatBotAutostart.userId, userId));
334	    } catch {
335	      /* ignore */
336	    }
337	    this.autostartCache.delete(userId);
338	    removeUserWechatStorage(userId);
339	    await cronService.removeAllByUser(userId);
340	    await reminderService.removeAllByUser(userId);
341	    await agentService.remove(userId);
342	    console.log(`[bot user:${userId}] 已停止并清除凭据、定时任务、提醒、对话`);
343	  }
344	}
345	
346	export const botService = new BotService();
