68	function extractReply(messages: AgentMessage[]): string {
69	  const last = [...messages]
70	    .reverse()
71	    .find((m): m is AssistantMessage => m.role === "assistant");
72	  if (!last) return "";
73	  const text = last.content
74	    .filter((b): b is TextContent => b.type === "text")
75	    .map((b) => b.text)
76	    .join("");
77	  if (last.stopReason === "error" && last.errorMessage) {
78	    return text || last.errorMessage;
79	  }
80	  return text;
81	}
