261	    _buildRuntime: (opts?: {
262	      activeToolNames?: string[];
263	      includeAllExtensionTools?: boolean;
264	    }) => void;
265	  };
266	  patched._baseToolsOverride = {
267	    read: scopedRead as unknown as AgentTool,
268	    bash: scopedBash,
