355	  async prompt(
356	    userId: string,
357	    text: string,
358	    images?: ImageContent[],
359	    opts?: AgentPromptOptions,
360	  ): Promise<string> {
361	    const school = await this.schoolWorkflow.preparePromptInput(userId, text);
362	    const session = await this.getOrCreate(userId);
363	    this.touchActivity(userId);
364	
365	    /** 勿整表覆盖：pi-mcp-adapter 等扩展会注册 `mcp`、内置 `read` 等 */
366	    const replaceableNames = new Set<string>([
367	      ...CRON_TOOL_NAMES,
368	      ...WECHAT_MEDIA_TOOL_NAMES,
369	      ...BASH_TOOL_NAMES,
370	    ]);
371	    const kept = session.agent.state.tools.filter(
372	      (t) => !replaceableNames.has(t.name),
373	    );
374	
375	    const cron =
376	      opts?.cronTools !== false
377	        ? buildCronTools(userId, {
378	          defaultWechatTarget: opts?.defaultWechatTarget,
379	        })
380	        : [];
381	    const media = opts?.wechatBot
382	      ? buildWechatMediaTools(userId, opts.wechatBot, {
383	        defaultWechatTarget: opts?.defaultWechatTarget,
384	        incomingWechatMessage: opts?.wechatReplyMessage,
385	      })
386	      : [];
387	    const bash = createUserScopedBashTool(userId, school.identity);
388	    session.agent.state.tools = [...kept, ...cron, ...media, bash];
389	
390	    if (images?.length) {
391	      await session.prompt(school.inputText || "请看图片。", { images });
392	    } else {
393	      await session.prompt(school.inputText);
394	    }
395	
396	    const reply = stripMarkdown(extractReply(session.messages) || "");
397	    const capped = truncateMessagesTail(session.messages, maxStoredMessages());
398	    if (capped.length !== session.messages.length) {
399	      session.agent.state.messages = capped;
400	    }
401	    await this.persistJsonl(userId, capped);
402	    return reply;
403	  }
