405	  private async persistJsonl(
406	    userId: string,
407	    capped: AgentMessage[],
408	  ): Promise<void> {
409	    try {
410	      let st = this.sessionFileState.get(userId);
411	      if (!st) {
412	        const p = createNewSessionJsonlFile(userId);
413	        const n = persistMessagesToJsonl(p, capped, 0);
414	        this.sessionFileState.set(userId, { path: p, messageLinesOnDisk: n });
415	        return;
416	      }
417	      const n = persistMessagesToJsonl(st.path, capped, st.messageLinesOnDisk);
418	      this.sessionFileState.set(userId, { path: st.path, messageLinesOnDisk: n });
419	    } catch (e) {
420	      console.error(`[agent] user ${userId} jsonl 保存失败`, e);
421	    }
422	  }
