519	  private async buildTurn(
520	    userId: string,
521	    bot: WeChatBot,
522	    msg: IncomingMessage,
523	  ): Promise<{
524	    text: string;
525	    images?: ImageContent[];
526	    pendingSubmissionFile?: PendingSubmissionFile;
527	  }> {
528	    if (msg.type === "text") return { text: msg.text?.trim() ?? "" };
529	
530	    if (msg.type === "voice") {
531	      const stt = msg.voices[0]?.text?.trim();
532	      return stt
533	        ? { text: `（语音转文字）${stt}` }
534	        : { text: "用户发了语音，但没有转文字结果，请提示对方改用文字或图片。" };
535	    }
536	
537	    const media = await bot.download(msg);
538	    if (!media) return { text: `[${msg.type}] ${msg.text || ""}` };
539	
540	    if (media.type === "image") {
541	      const mime = guessImageMime(media.fileName);
