543	        msg.text?.replace(/^\[image\]\s*/i, "").trim() ||
544	        "请描述或回答与这张图片相关的问题。";
545	      const data = media.data.toString("base64");
546	      if (!isPlausibleImageBase64(data)) {
547	        return {
548	          text: `${caption}\n（图片数据为空，无法识别画面。）`,
549	        };
550	      }
551	      let savedNote = "";
552	      try {
