557	        );
558	        savedNote = `\n（图片已保存到用户目录，相对路径：${rel}，可用 read 读取。）`;
559	      } catch (e) {
560	        console.warn(`[agent user:${userId}] 保存微信图片失败`, e);
561	      }
562	      return {
563	        text: caption + savedNote,
564	        images: [{ type: "image", data, mimeType: mime }],
565	      };
566	    }
567	
568	    if (media.type === "video") {
569	      return { text: "用户发送了视频，请礼貌请对方改用图片或文字。" };
570	    }
571	
572	    const isImg = media.fileName?.match(/\.(png|jpe?g|gif|webp|bmp)$/i);
573	    if (isImg) {
574	      const data = media.data.toString("base64");
575	      const text = msg.text?.trim() || "请根据该图片文件协助用户。";
576	      if (!isPlausibleImageBase64(data)) {
