31	export function resolvePathUnderUserWechatMediaRoot(
32	  userId: string,
33	  userRelativePath: string,
34	): string {
35	  const root = path.resolve(wechatUserMediaRoot(userId));
36	  const trimmed = userRelativePath.trim().replace(/\\/g, "/");
37	  if (!trimmed || trimmed.includes("..")) {
38	    throw new Error("路径无效：不能为空或包含 ..");
39	  }
40	  const normalized = path.normalize(trimmed);
41	  if (path.isAbsolute(normalized)) {
42	    throw new Error("请使用相对路径（相对于当前用户可发送目录），不要使用绝对路径");
43	  }
44	  const resolved = path.resolve(root, normalized);
45	  const rel = path.relative(root, resolved);
46	  if (rel.startsWith("..") || path.isAbsolute(rel)) {
47	    throw new Error("路径必须在当前用户可发送目录内");
48	  }
49	  return resolved;
