500	    if (raw === "不提交" || raw.toLowerCase() === "/nosubmit") {
501	      this.clearPending(userId);
502	      await bot.reply(msg, "好的，这个文件不会作为作业提交。");
503	      return true;
504	    }
505	
506	    const quickSubmitMatch = raw.match(/^(?:submit\s+)?(\d+)$/i);
507	    if (quickSubmitMatch && this.hasPendingSubmission(userId)) {
508	      await this.handleSubmitCommand(userId, bot, msg, quickSubmitMatch[1] ?? "");
509	      return true;
510	    }
511	
512	    const submitMatch = raw.match(/^\/submit(?:\s+(.+))?$/i);
513	    if (submitMatch) {
514	      await this.handleSubmitCommand(userId, bot, msg, submitMatch[1] ?? "");
515	      return true;
516	    }
517	
518	    const quickPublishMatch = raw.match(/^(?:publish\s+)?(\d+)$/i);
519	    if (quickPublishMatch && this.hasPendingPublish(userId)) {
520	      await this.handlePublishCommand(userId, bot, msg, quickPublishMatch[1] ?? "");
521	      return true;
522	    }
523	
524	    const publishMatch = raw.match(/^\/publish(?:\s+(.+))?$/i);
525	    if (publishMatch) {
526	      await this.handlePublishCommand(userId, bot, msg, publishMatch[1] ?? "");
527	      return true;
528	    }
529	
530	    return false;
531	  }
532	}
